import './index.css';

import {
  useEffect,
  useState
} from 'react';

import Header
from '../../components/common/Header';

import {
  getStudentMarks
} from '../../services/marksService';

function StudentMarks() {

  const [marks, setMarks] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  // ======================================
  // LOAD MARKS
  // ======================================

  useEffect(() => {

    loadMarks();

  }, []);

  const loadMarks =
    async () => {

    try {

      const response =
        await getStudentMarks();

      console.log(
        'Marks Response:',
        response
      );

      // IMPORTANT FIX

      setMarks(

        response.marks || []

      );

    } catch (error) {

      console.log(error);

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="student-marks-page">

      {/* HEADER */}

      <Header />


      {/* CONTENT */}

      <div className="student-marks-content">

        <div className="marks-top">

          <h1>
            My Marks
          </h1>

          <p>
            View academic marks
          </p>

        </div>


        {

          loading
          ? (

            <div className="loading-box">

              Loading Marks...

            </div>

          )
          : (

            <div className="marks-grid">

              {

                marks.length > 0
                ? (

                  marks.map((mark) => (

                    <div
                      key={mark.id}
                      className="mark-card"
                    >

                      <div className="card-top">

                        <h3>

                          {

                            mark.subject_id

                          }

                        </h3>

                        <span className="grade-badge">

                          {mark.grade}

                        </span>

                      </div>

                      <div className="mark-info">

                        <p>

                          <strong>
                            Student ID:
                          </strong>

                          {' '}

                          {mark.student_id}

                        </p>

                        <p>

                          <strong>
                            Subject ID:
                          </strong>

                          {' '}

                          {mark.subject_id}

                        </p>

                        <p>

                          <strong>
                            Assessment ID:
                          </strong>

                          {' '}

                          {mark.assessment_id}

                        </p>

                        <p>

                          <strong>
                            Marks:
                          </strong>

                          {' '}

                          {mark.marks_obtained}

                        </p>

                        <p>

                          <strong>
                            Percentage:
                          </strong>

                          {' '}

                          {mark.percentage}%

                        </p>

                      </div>

                    </div>

                  ))

                )
                : (

                  <div className="empty-box">

                    No Marks Available

                  </div>

                )

              }

            </div>

          )

        }

      </div>

    </div>

  );

}

export default StudentMarks;
